#!/usr/bin/perl

use CGI qw/:standard/;

my $cgi = CGI->new();
my $filename = $cgi->param('logfile');
my $log_dir = '/path/to/log/directory';

open(FH, "$log_dir/$filename") or die "Could not open log file: $!";

print $cgi->header('text/html');
print "<pre>";

while (<FH>) {
    print $_;
}

close(FH);

print "</pre>";

print $cgi->end_html;
